// Estrae i dati essenziali dalla mail per la classificazione
const item = $input.first();
const mail = item.json;

const mittente = mail.from || '';
const oggetto  = mail.subject || '';
const corpo    = mail.text || mail.html || '';

// Conta allegati PDF
const tutteLeChiavi = Object.keys(item.json);
const allegatiPdf = tutteLeChiavi.filter(k => k.startsWith('attachment_') && 
  (item.json[k]?.mimeType === 'application/pdf' || 
   (item.json[k]?.fileName || '').toLowerCase().endsWith('.pdf')));

return [{
  json: {
    mittente,
    oggetto,
    corpo: corpo.substring(0, 2000),
    haAllegatiPdf: allegatiPdf.length > 0,
    numAllegatiPdf: allegatiPdf.length,
    chiaviallegati: allegatiPdf,
    dataRicezione: new Date().toISOString()
  },
  binary: item.binary
}];

const item = $input.first();
const risposta = item.json?.choices?.[0]?.message?.content?.trim().toUpperCase() || 'INFO';
const categorie = ['ORDINE','OFFERTA','APPROVVIGIONAMENTO','SPAM','INFO'];
const categoria = categorie.find(c => risposta.includes(c)) || 'INFO';

return [{
  json: {
    ...item.json,
    classificazione: categoria
  }
}];

// Estrae il nome del cliente dal mittente email
const item = $input.first();
const mittente = item.json.mittente || '';

// Estrae nome dal formato: "Nome Cognome <email@dominio.it>"
let nomeCliente = 'CLIENTE_SCONOSCIUTO';
const matchNome = mittente.match(/^([^<]+)/);
if (matchNome) {
  nomeCliente = matchNome[1].trim()
    .toUpperCase()
    .replace(/[^A-Z0-9\s]/g, '')
    .replace(/\s+/g, '_')
    .substring(0, 30);
}

if (!nomeCliente || nomeCliente.length < 2) {
  // Fallback: usa dominio email
  const matchEmail = mittente.match(/@([^.>]+)/);
  nomeCliente = matchEmail ? matchEmail[1].toUpperCase() : 'CLIENTE_SCONOSCIUTO';
}

const timestamp = new Date().toISOString().replace(/[:.]/g, '-').substring(0, 19);
const cartellaCliente = `/data/valutazione/${nomeCliente}`;
const cartellaSessione = `${cartellaCliente}/${timestamp}`;

return [{
  json: {
    ...item.json,
    nomeCliente,
    cartellaCliente,
    cartellaSessione,
    timestamp
  },
  binary: item.binary
}];

// Prepara la lista degli allegati PDF da processare
const item = $input.first();
const chiavi = item.json.chiaviallegati || [];

if (chiavi.length === 0) {
  return [{ json: { ...item.json, errore: 'Nessun allegato PDF trovato' } }];
}

// Crea un item per ogni allegato PDF
return chiavi.map((chiave, index) => {
  const allegato = item.json[chiave] || {};
  const nomeFile = (allegato.fileName || `disegno_${index + 1}.pdf`)
    .toUpperCase()
    .replace(/\s+/g, '_');

  return {
    json: {
      ...item.json,
      chiaveAllegato: chiave,
      nomeFilePdf: nomeFile,
      nomeFilePdfBase: nomeFile.replace('.PDF', ''),
      percorsoFilePdf: `${item.json.cartellaSessione}/${nomeFile}`,
      percorsoFilePng: `${item.json.cartellaSessione}/${nomeFile.replace('.PDF', '.PNG')}`,
      indiceAllegato: index + 1,
      totaleAllegati: chiavi.length
    },
    binary: item.binary
  };
});

// Salva il PDF allegato su disco
const item = $input.first();
const fs = require('fs');

try {
  const chiave = item.json.chiaveAllegato;
  const binaryData = item.binary?.[chiave];

  if (!binaryData) {
    throw new Error(`Binary data non trovato per chiave: ${chiave}`);
  }

  // Decodifica base64 e salva
  const buffer = Buffer.from(binaryData.data, 'base64');
  fs.writeFileSync(item.json.percorsoFilePdf, buffer);

  return [{
    json: {
      ...item.json,
      pdfSalvato: true,
      dimensionePdf: buffer.length
    }
  }];
} catch(e) {
  return [{
    json: {
      ...item.json,
      pdfSalvato: false,
      errore: e.message
    }
  }];
}

// Legge il PNG e lo converte in base64 per Groq Vision
const item = $input.first();
const fs = require('fs');

try {
  const percorsoPng = item.json.percorsoFilePng;

  if (!fs.existsSync(percorsoPng)) {
    throw new Error(`PNG non trovato: ${percorsoPng}`);
  }

  const buffer = fs.readFileSync(percorsoPng);
  const base64 = buffer.toString('base64');

  return [{
    json: {
      ...item.json,
      pngBase64: base64,
      pngLetto: true
    }
  }];
} catch(e) {
  return [{
    json: {
      ...item.json,
      pngLetto: false,
      errore: e.message
    }
  }];
}

// Parsa il JSON restituito da Groq e lo salva su disco
const item = $input.first();
const fs = require('fs');

try {
  let testoRisposta = item.json?.choices?.[0]?.message?.content || '{}';

  // Rimuove eventuali markdown code fences
  testoRisposta = testoRisposta
    .replace(/```json/gi, '')
    .replace(/```/g, '')
    .trim();

  const analisi = JSON.parse(testoRisposta);

  // Salva JSON analisi su disco
  const percorsoJson = item.json.percorsoFilePdf.replace('.PDF', '_ANALISI.json').replace('.pdf', '_ANALISI.json');
  fs.writeFileSync(percorsoJson, JSON.stringify(analisi, null, 2), 'utf8');

  return [{
    json: {
      ...item.json,
      analisi,
      percorsoJson,
      analisiOk: true,
      fasiTesto: analisi.fasi_testo || 'N/D',
      problematiche: analisi.problematiche_testo || 'Nessuna'
    }
  }];
} catch(e) {
  return [{
    json: {
      ...item.json,
      analisiOk: false,
      errore: `Errore parsing JSON Groq: ${e.message}`,
      rispostaGrezzo: item.json?.choices?.[0]?.message?.content
    }
  }];
}

// Annota il PDF con le fasi estratte usando ghostscript
// Genera uno script ps per aggiungere testo al PDF
const item = $input.first();
const fs = require('fs');

try {
  const analisi = item.json.analisi || {};
  const fasi = analisi.fasi || [];
  const percorsoPdfInput = item.json.percorsoFilePdf;
  const percorsoPdfOutput = percorsoPdfInput.replace('.PDF', '_ANNOTATO.PDF').replace('.pdf', '_ANNOTATO.pdf');

  // Costruisce il testo annotazione
  const righeAnnotazione = [];
  righeAnnotazione.push(`CODICE: ${analisi.codice || 'N/D'}  |  MATERIALE: ${analisi.materiale || 'N/D'}  |  SP: ${analisi.spessore_mm || 'N/D'} mm`);
  righeAnnotazione.push(`DESCRIZIONE: ${analisi.descrizione || 'N/D'}`);
  righeAnnotazione.push(`CICLO: ${analisi.fasi_testo || 'N/D'}`);
  if (analisi.trattamenti && analisi.trattamenti.length > 0) {
    const tratt = analisi.trattamenti.map(t => t.tipo).join(', ');
    righeAnnotazione.push(`TRATTAMENTI: ${tratt}`);
  }
  if (analisi.saldatura) {
    righeAnnotazione.push('⚠️ SALDATURA: ESTERNALIZZARE');
  }
  if (analisi.problematiche_testo && analisi.problematiche_testo !== 'Nessuna') {
    righeAnnotazione.push(`⚠️ PROBLEMATICHE: ${analisi.problematiche_testo}`);
  }

  // Salva testo annotazione come file separato
  const percorsoTxt = percorsoPdfInput.replace('.PDF', '_CICLO.txt').replace('.pdf', '_CICLO.txt');
  fs.writeFileSync(percorsoTxt, righeAnnotazione.join('\n'), 'utf8');

  return [{
    json: {
      ...item.json,
      percorsoPdfOutput,
      percorsoTxt,
      righeAnnotazione,
      pdfProntoPerAnnotazione: true
    }
  }];
} catch(e) {
  return [{
    json: {
      ...item.json,
      pdfProntoPerAnnotazione: false,
      errore: e.message
    }
  }];
}

// Log finale dell'elaborazione
const item = $input.first();
const output = item.json?.stdout || '';
const annotazioneOk = output.includes('ANNOTAZIONE_OK');

const riepilogo = {
  cliente: item.json.nomeCliente,
  file: item.json.nomeFilePdf,
  cartella: item.json.cartellaSessione,
  codice: item.json.analisi?.codice || 'N/D',
  materiale: item.json.analisi?.materiale || 'N/D',
  spessore: item.json.analisi?.spessore_mm || 'N/D',
  ciclo: item.json.analisi?.fasi_testo || 'N/D',
  problematiche: item.json.analisi?.problematiche_testo || 'Nessuna',
  annotazioneOk,
  timestamp: item.json.timestamp,
  fileGenerati: [
    item.json.percorsoFilePdf,
    item.json.percorsoFilePng,
    item.json.percorsoJson,
    item.json.percorsoTxt,
    item.json.percorsoPdfOutput
  ]
};

console.log('=== ELABORAZIONE COMPLETATA ===');
console.log(JSON.stringify(riepilogo, null, 2));

return [{ json: riepilogo }];

// Mail ignorata — non è ordine/offerta
const item = $input.first();
console.log(`Mail ignorata - Classificazione: ${item.json.classificazione} - Da: ${item.json.mittente}`);
return [{ json: { ...item.json, azione: 'IGNORATA', motivo: 'Non è ordine o offerta' } }];

// Ordine/offerta senza allegati PDF
const item = $input.first();
console.log(`Ordine/Offerta senza PDF - Da: ${item.json.mittente} - Oggetto: ${item.json.oggetto}`);
return [{ json: { ...item.json, azione: 'SENZA_PDF', motivo: 'Ordine/offerta ricevuto ma senza allegati PDF' } }];
